      "level": 3,
      "code": "____ useBudget() {\n  const [txs, setTxs] = useState<Transaction[]>([]);\n\n  // CREATE\n  const add = (t: Omit<Transaction, 'id'>) => {\n    setTxs(prev => [...prev, { ...t, id: Date.now() } as Transaction]);\n  };\n\n  // READ\n  const find = (id: number) => txs.find(t => t.id === id);\n\n  // UPDATE\n  const update = (id: number, updates: Partial<Transaction>) => {\n    setTxs(prev => prev.map(t => (t.id === id ? { ...t, ...updates } as Transaction : t)));\n  };\n\n  // DELETE\n  const remove = (id: number) => {\n    setTxs(prev => prev.filter(t => t.id !== id));\n  };\n\n  return { txs, add, find, update, remove };\n}",
